let written = 0;
for (const [foodType, items] of Object.entries(additions)) {
  for (const item of items) {
    const food = {
      id: item.id,
      name: item.name,
      foodType,
      basis: { value: 100, unit: 'g' },
      header: Object.fromEntries(Object.entries(item.header).map(([k, v]) => [k, round1(v)])),
      metrics: metrics(item.metrics),
      contextItems: context(baseContexts[foodType], item.extra || {}),
      expectedTier: null,
      sourceNotes: [
        'Calibration benchmark sample for FoodRanked.',
        'Values are approximate representative placeholders for ruleset tuning, not a clinical nutrient database.'
      ]
    };
    if (typeof item.processingPenalty === 'number') food.processingPenalty = item.processingPenalty;
    fs.writeFileSync(path.join(foodsDir, `${item.id}.sample.json`), JSON.stringify(food, null, 2) + '\n');
    written += 1;
  }
}

console.log(JSON.stringify({ status: 'ok', written }, null, 2));
